#include <iostream>

class Monster
{
    int m_hp{};
public:
    Monster(int hp) : m_hp{hp} {}
    virtual int threat() const { return m_hp; }
    virtual ~Monster() = default;
};

class Boss : public Monster
{
    int m_rage{};
public:
    Boss(int hp, int rage) : Monster{hp}, m_rage{rage} {}
    int threat() const override { return Monster::threat() + m_rage; }
};

int main()
{
    int hp{}, rage{};
    std::cin >> hp >> rage;

    Boss boss{hp, rage};
    std::cout << "Direct: " << boss.threat() << '\n';

    const Monster& ref{boss};
    std::cout << "Ref: " << ref.threat() << '\n';

    Monster sliced{boss};
    std::cout << "Sliced: " << sliced.threat() << '\n';
    return 0;
}

