#include <iostream>
#include <memory>
#include <string>
#include <vector>

class Employee
{
    int m_base{};
public:
    Employee(int base) : m_base{base} {}
    virtual int pay() const { return m_base; }
    virtual ~Employee() = default;
};

class Manager : public Employee
{
    int m_bonus{};
public:
    Manager(int base, int bonus) : Employee{base}, m_bonus{bonus} {}
    int pay() const override { return Employee::pay() + m_bonus; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Employee> sliced{};
    std::vector<std::unique_ptr<Employee>> poly{};

    for (int i{0}; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "manager")
        {
            int base{}, bonus{};
            std::cin >> base >> bonus;
            Manager m{base, bonus};
            sliced.push_back(m);
            poly.push_back(std::make_unique<Manager>(base, bonus));
        }
        else
        {
            int base{};
            std::cin >> base;
            Employee e{base};
            sliced.push_back(e);
            poly.push_back(std::make_unique<Employee>(base));
        }
    }

    int slicedTotal{0};
    for (const auto& e : sliced)
        slicedTotal += e.pay();

    int polyTotal{0};
    for (const auto& e : poly)
        polyTotal += e->pay();

    std::cout << "Sliced total: " << slicedTotal << '\n';
    std::cout << "Polymorphic total: " << polyTotal << '\n';
    return 0;
}
